SELECT c.id, c.post_id AS postId, c.user_id AS userId, c.content, c.parent_id AS parentId, c.reply_user_id AS replyUserId, c.like_count AS likeCount, c.status, c.create_time AS createTime, c.is_author AS isAuthor FROM comment c WHERE c.post_id = #{postId} AND c.parent_id = 0 AND c.status = 1
AND c.id < #{lastId}
ORDER BY c.id DESC LIMIT #{pageSize}

SELECT c.id, c.post_id AS postId, c.user_id AS userId, c.content, c.parent_id AS parentId, c.reply_user_id AS replyUserId, c.like_count AS likeCount, c.status, c.create_time AS createTime, c.is_author AS isAuthor FROM comment c WHERE c.parent_id = #{parentId} AND c.status = 1
AND c.id > #{lastId}
ORDER BY c.id ASC LIMIT #{pageSize}

SELECT COUNT(*) FROM comment
WHERE parent_id = #{commentId}
  AND post_id = #{postId}
  AND status = 1

mapper.update:
UPDATE comment
SET status = 0
WHERE id = #{id}

UPDATE comment
SET like_count = like_count + 1
WHERE id = #{commentId}

UPDATE comment
SET like_count = like_count - 1
WHERE id = #{commentId}
